insert into master.m_move_pattern_rule (
  move_pattern_id,
  rule_type,
  priority,
  params_json,
  is_active,
  created_at,
  updated_at
)
select
  mp.move_pattern_id,
  src.rule_type,
  src.priority,
  src.params_json,
  true,
  now(),
  now()
from (
  values
  ('moon', 'turn_parity_override', 10, '{"odd":{"type":"step_limit","max_step":1,"rays":"queen"},"even":{"type":"step_limit","min_step":2,"max_step":2,"rays":"queen"},"source":"piece_info_canMoveToMoonOddEven"}'::jsonb),
  ('mirror', 'copy_front_enemy_move', 10, '{"source":"piece_skill_text"}'::jsonb),
  ('film', 'copy_front_enemy_move', 10, '{"source":"piece_skill_text"}'::jsonb),
  ('book', 'copy_last_enemy_move', 10, '{"source":"piece_skill_text"}'::jsonb),
  ('house', 'immobile', 0, '{"source":"piece_info_canMoveTo_false"}'::jsonb),
  ('field', 'immobile', 0, '{"source":"piece_info_canMoveTo_false"}'::jsonb),
  ('mutant', 'immobile', 0, '{"source":"piece_info_canMoveTo_false"}'::jsonb)
) as src(move_code, rule_type, priority, params_json)
join master.m_move_pattern as mp
  on mp.move_code = src.move_code;

